import React from 'react';
import { useNavigate } from 'react-router-dom';

interface ReviewQuestion {
  field: string;
  question: string;
  answer: string | null;
  type?: string;
}

interface ReviewSummaryProps {
  sectionId: string;
  sectionTitle: string;
  questions: ReviewQuestion[];
  onChangeSection: (sectionId: string) => void;
}

export function ReviewSummary({
  sectionId,
  sectionTitle,
  questions,
  onChangeSection
}: ReviewSummaryProps) {
  const formatAnswer = (answer: string | null, type?: string): string => {
    if (answer === null || answer === '' || answer === undefined) {
      return 'Not provided';
    }
    if (type === 'date') {
      return new Date(answer).toLocaleDateString('en-CA', {
        year: 'numeric',
        month: 'long',
        day: 'numeric'
      });
    }
    if (type === 'phone') {
      // Format as (780) 555-0123
      const cleaned = answer.replace(/\D/g, '');
      if (cleaned.length === 10) {
        return `(${cleaned.slice(0, 3)}) ${cleaned.slice(3, 6)}-${cleaned.slice(6)}`;
      }
    }
    return answer;
  };

  return (
    <div className="review-section">
      <div className="review-section__header">
        <h3>{sectionTitle}</h3>
        <button
          type="button"
          className="change-link"
          onClick={() => onChangeSection(sectionId)}
          aria-label={`Change ${sectionTitle} answers`}
        >
          Change
          <span className="visually-hidden"> {sectionTitle}</span>
        </button>
      </div>

      <dl className="review-list">
        {questions.map((q) => (
          <div key={q.field} className="review-item">
            <dt className="review-item__question">{q.question}</dt>
            <dd className={
              `review-item__answer ${!q.answer ? 'review-item__answer--empty' : ''}`
            }>
              {formatAnswer(q.answer, q.type)}
            </dd>
          </div>
        ))}
      </dl>
    </div>
  );
}

// Example usage:
function ReviewPage() {
  const navigate = useNavigate();

  const personalInfoData: ReviewQuestion[] = [
    { field: 'fullName', question: 'What is your full legal name?', answer: 'Sarah Elizabeth Johnson' },
    { field: 'dateOfBirth', question: 'What is your date of birth?', answer: '1985-06-15', type: 'date' },
    { field: 'sinNumber', question: 'What is your Social Insurance Number?', answer: '123-456-789' }
  ];

  const contactInfoData: ReviewQuestion[] = [
    { field: 'email', question: 'What is your email address?', answer: 'sarah.johnson@email.com' },
    { field: 'phone', question: 'What is your phone number?', answer: '7805550123', type: 'phone' },
    { field: 'preferredContact', question: 'How would you prefer we contact you?', answer: 'Email' }
  ];

  const addressData: ReviewQuestion[] = [
    { field: 'streetAddress', question: 'What is your street address?', answer: '456 Maple Street' },
    { field: 'city', question: 'City or town', answer: 'Edmonton' },
    { field: 'province', question: 'Province', answer: 'Alberta' },
    { field: 'postalCode', question: 'Postal code', answer: 'T5K 2P3' }
  ];

  const handleChangeSection = (sectionId: string) => {
    navigate(`/apply/step/${sectionId}?return=review`);
  };

  return (
    <div className="form-page">
      <h1 className="step-title">Review your application</h1>
      <p className="step-description">
        Check your answers before submitting. You can change any answer by clicking the Change link.
      </p>

      <ReviewSummary
        sectionId="personal-info"
        sectionTitle="Personal Information"
        questions={personalInfoData}
        onChangeSection={handleChangeSection}
      />

      <ReviewSummary
        sectionId="contact-info"
        sectionTitle="Contact Information"
        questions={contactInfoData}
        onChangeSection={handleChangeSection}
      />

      <ReviewSummary
        sectionId="address"
        sectionTitle="Address"
        questions={addressData}
        onChangeSection={handleChangeSection}
      />
    </div>
  );
}

